// ... 기존 import 유지
// KakaoMap 컴포넌트는 지도 표시용으로만 사용 (마커는 DB 데이터로 찍어야 함)

export default function PharmacyPage() {
  const [pharmacies, setPharmacies] = useState<Place[]>([]);
  // ...

  // ✅ 변경점: 컴포넌트 마운트 시 백엔드 DB에서 데이터 조회
  useEffect(() => {
    const fetchFromDB = async () => {
      try {
        setIsLoading(true);
        // 우리 백엔드 API 호출
        const res = await fetch("http://localhost:8080/api/pharmacies");
        const data = await res.json();
        
        // 백엔드 필드명을 프론트 인터페이스에 맞게 매핑 (필요시)
        const mappedData = data.map((item: any) => ({
            id: item.id,
            place_name: item.placeName,
            road_address_name: item.roadAddressName,
            address_name: item.addressName,
            phone: item.phone,
            x: item.x,
            y: item.y,
            place_url: item.placeUrl,
            QT: item.qt, // DB에 저장된 영업시간
            category_name: "의료,건강 > 약국", // DB에 없으면 하드코딩 혹은 저장 필요
            distance: "0", // DB조회라 거리는 계산 필요(선택사항)
        }));

        setPharmacies(mappedData);
      } catch (err) {
        console.error("DB 조회 실패:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchFromDB();
  }, []);

  // ... 나머지 렌더링 로직은 그대로 유지 ...
}